import React from "react"
import "./MemberRightsDuties.scss"
import ListSection from "./components/ListSection/ListSection"

function MemberRights() {
  const memberRights = [
    "Được Hiệp hội bảo vệ quyền, lợi ích hợp pháp theo quy định của pháp luật.",
    "Được Hiệp hội cung cấp thông tin liên quan đến lĩnh vực hoạt động của Hiệp hội, được tham gia các hoạt động do Hiệp hội tổ chức theo quy định của pháp luật và Điều lệ Hiệp hội.",
    "Được tham gia thảo luận, quyết định các chủ trương công tác của Hiệp hội theo quy định của Hiệp hội; được kiến nghị, đề xuất ý kiến với cơ quan có thẩm quyền về những vấn đề có liên quan đến lĩnh vực hoạt động của Hiệp hội.",
    "Được dự Đại hội, ứng cử, đề cử, bầu cử vào Ban Chấp hành, Ban Kiểm tra Hiệp hội theo quy định của Hiệp hội.",
    "Được giới thiệu hội viên mới.",
    "Được khen thưởng theo quy định của Hiệp hội.",
    "Được cấp thẻ hội viên (nếu có).",
    "Được ra khỏi Hiệp hội khi xét thấy không thể tiếp tục là hội viên.",
    "Được bồi dưỡng về quy chế chuyên môn nghiệp vụ, được khuyến khích phát huy khả năng về mọi mặt để phục vụ nhân dân.",
    "Được trình bày các đề tài nghiên cứu khoa học của mình trong các buổi sinh hoạt khoa học kỹ thuật của Hiệp hội.",
    "Được Hiệp hội nhận xét về công trình, tác phẩm của mình, khi cần thiết được đề nghị chính quyền khen thưởng hoặc công nhận, bảo vệ quyền tác giả sáng tác.",
    "Hội viên liên kết, hội viên danh dự được hưởng quyền và nghĩa vụ như hội viên chính thức, trừ quyền biểu quyết các vấn đề của Hiệp hội và quyền ứng cử, đề cử, bầu cử Ban Chấp hành, Ban Kiểm tra Hiệp hội",
  ]

  const memberDuties = [
    "Nghiêm chỉnh chấp hành chủ trương, đường lối của Đảng, chính sách, pháp luật của Nhà nước. Tôn trọng Điều lệ Hiệp hội, nghiêm chỉnh chấp hành chỉ đạo, quy định của Hiệp hội và nghị quyết của Ban Chấp hành, Ban Thường vụ.",
    "Tham gia các hoạt động và sinh hoạt của Hiệp hội; đoàn kết, hợp tác với các hội viên khác để xây dựng Hiệp hội phát triển vững mạnh.",
    "Bảo vệ uy tín của Hiệp hội, không được nhân danh Hiệp hội trong các quan hệ giao dịch, trừ khi được lãnh đạo Hiệp hội phân công bằng văn bản.",
    "Tuyên truyền phát triển hội viên, vận động quần chúng hưởng ứng mọi hoạt động của Hiệp hội theo quy định của pháp luật.",
    "Chăm lo xây dựng đoàn kết nội bộ Hiệp hội để xây dựng lĩnh vực trong lĩnh vực tư vấn và hỗ trợ nâng cao sức khỏe thể chất và tinh thần, lối sống để phòng chống bệnh lây nhiễm, không lây nhiễm, bệnh nghề nghiệp và bệnh mới nổi trong ngành y tế",
    "Tích cực học tập chính trị, văn hóa, chuyên môn, nghiệp vụ, nhất là những kinh nghiệm tốt trong lĩnh vực tư vấn, truyền thông, nghiên cứu khoa học, ứng dụng Al chuyên đổi số trong đào tạo hội viên, giữ gìn sự trong sáng của y đức, xây dựng môi trường hoạt động chuyên nghiệp, tiến bộ, hiện đại vì sự nghiệp chăm sóc, bảo vệ và tăng cường sức khỏe nhân dân.",
    "Đấu tranh chống những tư tưởng, hành động có hại đến uy tín, quyền và lợi ích hợp pháp, chính đáng của Hiệp hội.",
    "Chủ trì tổ chức hoặc tham gia tổ chức các hội nghị, hội thảo khoa học trong lĩnh vực tư vấn và hỗ trợ nâng cao sức khỏe thể chất và tinh thần, lối sống để phòng chống bệnh lây nhiễm, không lây nhiễm, bệnh nghề nghiệp và bệnh mới nổi trong ngành y tế.",
    "Thực hiện chế độ thông tin, báo cáo theo quy định của Hiệp hội.",
    "Đóng hội phí đầy đủ và đúng hạn theo quy định của Hiệp hội.",
    "Phải bàn giao lại công việc và tài chính, tài sản, có liên quan khi không còn hoạt động ở Hiệp hội.",
  ]

  return (
    <div className="page-background">
      <div className="member-rights">
        <ListSection title="Quyền của hội viên" items={memberRights} />
        <ListSection title="Nghĩa Vụ của Hội Viên" items={memberDuties} />
      </div>
    </div>
  )
}

export default MemberRights
